INSERT INTO `workflow_comment_history` (`id`, `log_table`, `log_name`, `month`, `year`, `action_type`, `comment_text`, `done_by`, `done_at`) VALUES
(57, 'server_logs', 'Server Logs', 3, 2026, 'submit', 'ระบบตู้เสื้อผ้าอัตโนมัติควบคุมด้วยไมโครคอนโทรลเลอร์นี้ถูกออกแบบมาเพื่อเพิ่มความสะดวกสบายในการใช้งานสำหรับผู้ใช้ทุกช่วงวัย โดยเฉพาะผู้สูงอายุ ซึ่งอาจมีข้อจำกัดในการเคลื่อนไหวหรือการใช้งานอุปกรณ์ต่าง ๆ ภายในบ้าน ระบบสามารถตรวจจับการเคลื่อนไหวผ่านเซ็นเซอร์อินฟราเรด และสั่งการให้ประตูตู้เปิด-ปิดอัตโนมัติด้วยเซอร์โวมอเตอร์ ช่วยลดแรงที่ต้องใช้ในการเปิดตู้แบบเดิม\n\nนอกจากนี้ ภายในตู้ยังมีระบบไฟอัตโนมัติที่เปิดทันทีเมื่อมีการใช้งาน และปิดเมื่อไม่มีการใช้งาน เพื่อช่วยประหยัดพลังงานและเพิ่มความสะดวกในการมองเห็นเสื้อผ้าในที่แสงน้อย อีกทั้งยังมีระบบตรวจวัดความชื้น ซึ่งสามารถแจ้งเตือนผู้ใช้ผ่านเสียง buzzer เมื่อระดับความชื้นสูงเกินค่าที่กำหนด เพื่อป้องกันปัญหาเชื้อราและกลิ่นอับภายในตู้\n\nระบบยังรองรับการปรับระดับราวแขวนเสื้อผ้าได้ 3 ระดับ ได้แก่ สูง กลาง และต่ำ โดยสามารถควบคุมผ่านรีโมทคอนโทรล ทำให้เหมาะสมกับผู้ใช้ที่มีความสูงหรือความสามารถในการเอื้อมถึงที่แตกต่างกัน การออกแบบทั้งหมดนี้คำนึงถึงหลัก Ergonomics เพื่อให้ผู้ใช้งานรู้สึกสะดวก ปลอดภัย และลดความเสี่ยงในการเกิดอุบัติเหตุภายในบ้าน\n\nในส่วนของซอฟต์แวร์ ระบบถูกพัฒนาโดยใช้ไมโครคอนโทรลเลอร์ ESP32 ซึ่งมีความสามารถในการประมวลผลที่รวดเร็ว และรองรับการเชื่อมต่อกับอุปกรณ์ต่าง ๆ ได้อย่างมีประสิทธิภาพ พร้อมทั้งมีการออกแบบโครงสร้างโปรแกรมให้สามารถขยายต่อยอดในอนาคตได้ เช่น การเชื่อมต่อกับแอปพลิเคชันบนมือถือ หรือการเก็บข้อมูลการใช้งานเพื่อวิเคราะห์พฤติกรรมของผู้ใช้\n\nโดยรวมแล้ว โครงงานนี้ไม่เพียงแต่ช่วยอำนวยความสะดวก แต่ยังเป็นการนำเทคโนโลยีมาประยุกต์ใช้ในชีวิตประจำวันได้อย่างเหมาะสม และสามารถพัฒนาเป็นผลิตภัณฑ์จริงในเชิงพาณิชย์ได้ในอนาคต', 'Aekkarat Mantati', '2026-03-18 09:47:55'),
